<script setup>
import{ref}from'vue';import{api}from'../../api';const current=ref(''),next=ref(''),confirm=ref(''),saving=ref(false)
async function save(){if(!current.value)return uni.showToast({title:'请输入当前密码',icon:'none'});if(!/^(?=.*[A-Za-z])(?=.*\d)\S{8,20}$/.test(next.value))return uni.showToast({title:'新密码须为8至20位且包含字母和数字',icon:'none'});if(next.value!==confirm.value)return uni.showToast({title:'两次输入的密码不一致',icon:'none'});saving.value=true;try{await api.changePassword({currentPassword:current.value,newPassword:next.value});uni.removeStorageSync('merchantToken');uni.removeStorageSync('merchantProfile');uni.showToast({title:'修改成功，请重新登录'});setTimeout(()=>uni.reLaunch({url:'/pages/merchant/login'}),1000)}catch(_){saving.value=false}}
</script>
<template><view class="page password-page"><view class="content"><view class="card form-card"><view class="field"><text class="field-label">当前密码</text><input v-model="current" class="input" password placeholder="请输入当前密码"/></view><view class="field"><text class="field-label">新密码</text><input v-model="next" class="input" password placeholder="请输入新密码"/></view><view class="field"><text class="field-label">确认新密码</text><input v-model="confirm" class="input" password placeholder="请再次输入新密码"/></view><view class="rule">密码规则：8-20位字符，至少包含字母和数字</view></view></view><view class="save-bar"><button class="primary-btn" :disabled="saving" @tap="save">{{saving?'保存中…':'保存新密码'}}</button></view></view></template>
<style scoped>.password-page{padding-bottom:130rpx}.form-card{padding:30rpx}.rule{padding:20rpx;border-radius:14rpx;background:#f7f8fa;color:#999;font-size:22rpx;line-height:1.7}.save-bar{position:fixed;left:0;right:0;bottom:0;padding:16rpx 28rpx calc(16rpx + env(safe-area-inset-bottom));background:#fff}.save-bar button{width:100%}</style>
